package com.example.trackingapp;

import android.content.*;import android.database.sqlite.*;import org.json.*;

final class SQLiteDatabaseHack {
 static void updateTracker(TrackingDatabase helper,long id,String json) throws JSONException{SQLiteDatabase db=helper.getWritableDatabase();JSONObject root=new JSONObject(json);long now=System.currentTimeMillis();db.beginTransaction();try{ContentValues tv=new ContentValues();tv.put("name",root.getString("name"));tv.put("description",root.optString("description",""));tv.put("updatedAt",now);db.update("trackers",tv,"id=?",new String[]{""+id});db.delete("items","trackerId=?",new String[]{""+id});JSONArray items=root.getJSONArray("items");for(int i=0;i<items.length();i++){JSONObject it=items.getJSONObject(i);ContentValues iv=new ContentValues();iv.put("trackerId",id);iv.put("title",it.getString("title"));iv.put("sortOrder",it.optInt("order",i));long itemId=db.insert("items",null,iv);JSONArray fields=it.getJSONArray("fields");for(int f=0;f<fields.length();f++){JSONObject fj=fields.getJSONObject(f);ContentValues fv=new ContentValues();fv.put("itemId",itemId);fv.put("fieldKey",fj.getString("key"));fv.put("label",fj.optString("label",fj.getString("key")));fv.put("type",fj.getString("type"));fv.put("sortOrder",fj.optInt("order",f));if(fj.has("defaultValue")&&!fj.isNull("defaultValue"))fv.put("defaultValue",String.valueOf(fj.get("defaultValue")));fv.put("incrementValue",fj.optDouble("increment",1));fv.put("decimals",fj.optInt("decimals",1));fv.put("unit",fj.optString("unit",""));fv.put("required",fj.optBoolean("required",false)?1:0);fv.put("prefillFromPrevious",fj.optBoolean("prefillFromPrevious",false)?1:0);db.insert("fields",null,fv);}}db.setTransactionSuccessful();}finally{db.endTransaction();}}
}
